<template>
  <div>
    <a-layout>
      <a-layout-content
        :style="{ background: '#fff', padding: '24px', margin: 0, minHeight: '280px' }"
      >
        <p>
          <a-form layout="inline" :model="param">
            <a-form-item>
              <a-button type="primary" @click="add()">
                新增
              </a-button>
            </a-form-item>
          </a-form>
        </p>

        <a-table
          :columns="columns"
          :row-key="record => record.id"
          :data-source="level1"
          :pagination="false"
          :loading="loading"
        >
          <template #bodyCell="{ column, record }">
            <template v-if="column.dataIndex === 'action'">
              <a-space size="small">
                <a-button type="primary" @click="edit(record)">
                  编辑
                </a-button>
                <a-popconfirm
                  title="删除后不可以恢复，确认删除?"
                  ok-text="是"
                  cancel-text="否"
                  @confirm="handleDelete(record.id)"
                >
                  <a-button danger>
                    删除
                  </a-button>
                </a-popconfirm>
              </a-space>
            </template>
          </template>
        </a-table>
      </a-layout-content>
    </a-layout>

    <!-- 分类编辑模态框 -->
    <a-modal
      title="分类表单"
      v-model:visible="modalVisible"
      :confirm-loading="modalLoading"
      @ok="handleModalOk"
    >
      <a-form :model="category" :label-col="{ span: 6 }" :wrapper-col="{ span: 18 }">
        <a-form-item label="名称">
          <a-input v-model:value="category.name" />
        </a-form-item>

        <!-- 父分类下拉选择 -->
        <a-form-item label="父分类">
          <a-tree-select
            v-model:value="category.parent"
            style="width: 100%"
            :tree-data="treeSelectData"
            :field-names="{ children: 'children', label: 'name', key: 'id', value: 'id' }"
            placeholder="请选择父分类"
            allow-clear
            tree-default-expand-all
          />
        </a-form-item>

        <a-form-item label="排序">
          <a-input v-model:value="category.sort" />
        </a-form-item>
      </a-form>
    </a-modal>
  </div>
</template>

<script setup>
import axios from 'axios'
import { ref, onMounted } from 'vue'
import { message } from 'ant-design-vue'

// ---------- 数据定义 ----------
const level1 = ref([])
const allCategories = ref([]) // 扁平列表，用于下拉选项
const loading = ref(false)
const param = ref({})
const treeSelectData = ref([])

const columns = [
  { title: '名称', dataIndex: 'name' },
  { title: '父分类', dataIndex: 'parent' },
  { title: '排序', dataIndex: 'sort' },
  { title: '操作', key: 'action', dataIndex: 'action' }
]

// ---------- 模态框相关 ----------
const modalVisible = ref(false)
const modalLoading = ref(false)
const category = ref({})

// ---------- 树形结构转换函数 ----------
const buildTree = (list, parentId = 0) => {
  const pid = String(parentId)
  return list
    .filter(item => String(item.parent) === pid)
    .map(item => ({
      ...item,
      children: buildTree(list, item.id)
    }))
}

// ---------- 查询数据 ----------
const handleQuery = () => {
  loading.value = true
  axios.get('/category/all')
    .then((resp) => {
      loading.value = false
      const data = resp.data
      if (data.success) {
        const rawList = data.content || []
        allCategories.value = rawList // 保存扁平列表供下拉使用
        level1.value = buildTree(rawList, 0) // 构建树形结构
        // 构建树形下拉数据（深拷贝后加上"无"选项）
        treeSelectData.value = JSON.parse(JSON.stringify(level1.value))
        treeSelectData.value.unshift({ id: 0, name: '无' })
        console.log('树形结构：', level1.value)
      }
    })
    .catch(() => {
      loading.value = false
    })
}

// ---------- 新增 ----------
const add = () => {
  modalVisible.value = true
  category.value = {}
}

// ---------- 编辑 ----------
const edit = (record) => {
  modalVisible.value = true
  category.value = { ...record }
}

// ---------- 删除 ----------
const handleDelete = (id) => {
  console.log('id:', id)
  // 检查是否有子分类
  const hasChildren = allCategories.value.some(item => String(item.parent) === String(id))
  if (hasChildren) {
    message.warning('该分类包含子分类，不能删除！')
    return
  }

  axios.delete(`/category/delete/${id}`)
    .then((resp) => {
      if (resp.data.success) {
        message.success('删除成功')
        handleQuery()
      } else {
        message.error(resp.data.message || '删除失败')
      }
    })
    .catch(() => {
      message.error('删除失败，请重试')
    })
}

// ---------- 保存 ----------
const handleModalOk = () => {
  modalLoading.value = true
  axios.post('/category/save', category.value)
    .then((resp) => {
      const data = resp.data
      if (data.success) {
        modalLoading.value = false
        modalVisible.value = false
        handleQuery()
      }
    })
    .catch(() => {
      modalLoading.value = false
    })
}

// ---------- 生命周期 ----------
onMounted(() => {
  handleQuery()
})
</script>

<style scoped>
/* 自定义样式 */
</style>
